UPDATE TBL_MAGAM_INFO A
   SET A.LOCK_YN  = CASE WHEN A.LOCK_YN = 'Y' THEN 'N'
                         WHEN A.LOCK_YN = 'N' THEN 'Y'
                         ELSE A.LOCK_YN END
     , A.UPD_DTTM = NOW()
 WHERE A.HOSP_CD  = #{hosp_cd}
   AND A.MG_YEAR  = #{mg_year}
   AND A.MGMONTH  = #{mgmonth}
   AND A.MG_FLAG  = #{mg_flag}

mapper.select:
WITH ValidMonths AS ( SELECT JOBCODE , COUNT(DISTINCT CASE WHEN COALESCE(J_COUNT, 0) > 0 OR COALESCE(JAMOUNT, 0) > 0 THEN JOBYYMM END) AS month_count FROM TBL_REPORT_MST WHERE HOSP_CD = #{hosp_cd} AND JOBYYMM BETWEEN #{fr_yymm} AND #{endyymm} AND MAKE_FG = #{make_fg} GROUP BY JOBCODE ) SELECT M.JOBCODE AS jobcode,
/* fr_yymm - JAMOUNT 그대로, J_COUNT [J_COUNT%] */ CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0) = 0 AND COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.J_COUNT END), 0) = 0 THEN '자료없음' ELSE CONCAT( CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0) = 0 THEN '자료없음' ELSE FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0)) END, CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.J_COUNT END), 0) > 0 THEN CONCAT(' [', ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.J_COUNT END), 0), 2), '%]') ELSE '' END ) END AS fr_yymm,
/* midyymm */ CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0) = 0 AND COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.J_COUNT END), 0) = 0 THEN '자료없음' ELSE CONCAT( CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0) = 0 THEN '자료없음' ELSE FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0)) END, CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.J_COUNT END), 0) > 0 THEN CONCAT(' [', ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.J_COUNT END), 0), 2), '%]') ELSE '' END ) END AS midyymm,
/* endyymm */ CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0) = 0 AND COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.J_COUNT END), 0) = 0 THEN '자료없음' ELSE CONCAT( CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0) = 0 THEN '자료없음' ELSE FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0)) END, CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.J_COUNT END), 0) > 0 THEN CONCAT(' [', ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.J_COUNT END), 0), 2), '%]') ELSE '' END ) END AS endyymm,
/* avg_val 개별행: JAMOUNT 소수점1자리(ROUND 1), J_COUNT [소수점2자리%] */ CASE WHEN COALESCE(IF(VM.month_count > 0, ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / VM.month_count, 1), 0), 0) = 0 AND COALESCE(IF(VM.month_count > 0, ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.J_COUNT END) / VM.month_count, 2), 0), 0) = 0 THEN '자료없음' ELSE CONCAT( CASE WHEN COALESCE(IF(VM.month_count > 0, ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / VM.month_count, 1), 0), 0) = 0 THEN '자료없음' ELSE COALESCE(IF(VM.month_count > 0, ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / VM.month_count, 1), 0), 0) END, CASE WHEN COALESCE(IF(VM.month_count > 0, ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.J_COUNT END) / VM.month_count, 2), 0), 0) > 0 THEN CONCAT(' [', COALESCE(IF(VM.month_count > 0, ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.J_COUNT END) / VM.month_count, 2), 0), 0), '%]') ELSE '' END ) END AS avg_val,
COALESCE(SUM(ROUND(CASE WHEN M.JOBYYMM = #{endyymm} THEN FN_TA_HOSP(#{hosp_cd}, #{endyymm}, #{make_fg}, M.JOBCODE) END)), 0) AS ta_e_ym
FROM TBL_REPORT_MST M LEFT JOIN ValidMonths VM ON M.JOBCODE = VM.JOBCODE WHERE M.HOSP_CD = #{hosp_cd} AND M.JOBYYMM BETWEEN #{fr_yymm} AND #{endyymm} AND M.MAKE_FG = #{make_fg} GROUP BY M.JOBCODE
UNION ALL
SELECT 'T' AS jobcode,
/* fr_yymm 합계(T) - J_COUNT [정수%] */ CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0) = 0 AND COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.J_COUNT END), 0) = 0 THEN '자료없음' ELSE CONCAT( CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0) = 0 THEN '자료없음' ELSE FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0)) END, CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.J_COUNT END), 0) > 0 THEN CONCAT(' [', FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.J_COUNT END), 0)), '%]') ELSE '' END ) END AS fr_yymm,
/* midyymm 합계(T) */ CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0) = 0 AND COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.J_COUNT END), 0) = 0 THEN '자료없음' ELSE CONCAT( CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0) = 0 THEN '자료없음' ELSE FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0)) END, CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.J_COUNT END), 0) > 0 THEN CONCAT(' [', FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.J_COUNT END), 0)), '%]') ELSE '' END ) END AS midyymm,
/* endyymm 합계(T) */ CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0) = 0 AND COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.J_COUNT END), 0) = 0 THEN '자료없음' ELSE CONCAT( CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0) = 0 THEN '자료없음' ELSE FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0)) END, CASE WHEN COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.J_COUNT END), 0) > 0 THEN CONCAT(' [', FLOOR(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.J_COUNT END), 0)), '%]') ELSE '' END ) END AS endyymm,
/* avg_val 합계(T)행: JAMOUNT 소수점1자리(ROUND 1), J_COUNT [정수%] */ CASE WHEN COALESCE(ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / COALESCE(MAX(VM.month_count), 1), 1), 0) = 0 AND COALESCE(FLOOR(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.J_COUNT END) / COALESCE(MAX(VM.month_count), 1)), 0) = 0 THEN '자료없음' ELSE CONCAT( CASE WHEN COALESCE(ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / COALESCE(MAX(VM.month_count), 1), 1), 0) = 0 THEN '자료없음' ELSE COALESCE(ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / COALESCE(MAX(VM.month_count), 1), 1), 0) END, CASE WHEN COALESCE(FLOOR(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.J_COUNT END) / COALESCE(MAX(VM.month_count), 1)), 0) > 0 THEN CONCAT(' [', COALESCE(FLOOR(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.J_COUNT END) / COALESCE(MAX(VM.month_count), 1)), 0), '%]') ELSE '' END ) END AS avg_val,
0 AS ta_e_ym
FROM TBL_REPORT_MST M LEFT JOIN ValidMonths VM ON M.JOBCODE = VM.JOBCODE WHERE M.HOSP_CD = #{hosp_cd} AND M.JOBYYMM BETWEEN #{fr_yymm} AND #{endyymm} AND M.MAKE_FG = #{make_fg} ORDER BY jobcode;

WITH ValidMonths AS ( SELECT JOBCODE, COUNT(DISTINCT CASE WHEN COALESCE(JAMOUNT, 0) > 0 THEN JOBYYMM END) AS month_count FROM TBL_REPORT_MST WHERE HOSP_CD = #{hosp_cd} AND JOBYYMM BETWEEN #{fr_yymm} AND #{endyymm} AND MAKE_FG = #{make_fg} GROUP BY JOBCODE ), TotalSummaryMonthly AS ( SELECT JOBYYMM, SUM(CASE WHEN JOBCODE = 'A' THEN COALESCE(JAMOUNT, 0) ELSE 0 END) AS total_jinryo, SUM(CASE WHEN JOBCODE = 'D' THEN COALESCE(JAMOUNT, 0) ELSE 0 END) AS total_gumsa, SUM(CASE WHEN JOBCODE = 'G' THEN COALESCE(J_COUNT, 0) ELSE 0 END) AS total_inwon FROM TBL_REPORT_MST WHERE HOSP_CD = #{hosp_cd} AND JOBYYMM BETWEEN #{fr_yymm} AND #{endyymm} AND MAKE_FG = #{make_fg} AND JOBCODE IN ('A','D','G') GROUP BY JOBYYMM ), TaHospSummary AS ( SELECT JOBYYMM, SUM(CASE WHEN JOBCODE = 'A' THEN FN_TA_HOSP(#{hosp_cd}, JOBYYMM, #{make_fg}, JOBCODE) ELSE 0 END) AS ta_jinryo, SUM(CASE WHEN JOBCODE = 'D' THEN FN_TA_HOSP(#{hosp_cd}, JOBYYMM, #{make_fg}, JOBCODE) ELSE 0 END) AS ta_gumsa FROM TBL_REPORT_MST WHERE HOSP_CD <> #{hosp_cd} AND JOBYYMM BETWEEN #{fr_yymm} AND #{endyymm} AND MAKE_FG = #{make_fg} AND JOBCODE IN ('A','D') GROUP BY JOBYYMM ) SELECT M.JOBCODE AS jobcode,
/* fr_yymm */ CASE WHEN M.JOBCODE = 'G' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_inwon END), 0) > 0 THEN CONCAT('[ ', FORMAT(MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_inwon END), 0), ' ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0), 0)) WHEN M.JOBCODE = 'D' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_jinryo END), 0) > 0 AND ROUND((MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_gumsa END) / COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_jinryo END), 1)) * 100) > 0 THEN CONCAT('[ ', ROUND((MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_gumsa END) / COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_jinryo END), 1)) * 100), '% ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0), 0)) ELSE FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN M.JAMOUNT END), 0), 0) END AS fr_yymm,
/* midyymm */ CASE WHEN M.JOBCODE = 'G' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_inwon END), 0) > 0 THEN CONCAT('[ ', FORMAT(MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_inwon END), 0), ' ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0), 0)) WHEN M.JOBCODE = 'D' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_jinryo END), 0) > 0 AND ROUND((MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_gumsa END) / COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_jinryo END), 1)) * 100) > 0 THEN CONCAT('[ ', ROUND((MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_gumsa END) / COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_jinryo END), 1)) * 100), '% ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0), 0)) ELSE FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN M.JAMOUNT END), 0), 0) END AS midyymm,
/* endyymm */ CASE WHEN M.JOBCODE = 'G' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_inwon END), 0) > 0 THEN CONCAT('[ ', FORMAT(MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_inwon END), 0), ' ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0), 0)) WHEN M.JOBCODE = 'D' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_jinryo END), 0) > 0 AND ROUND((MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_gumsa END) / COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_jinryo END), 1)) * 100) > 0 THEN CONCAT('[ ', ROUND((MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_gumsa END) / COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_jinryo END), 1)) * 100), '% ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0), 0)) ELSE FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN M.JAMOUNT END), 0), 0) END AS endyymm,
/* avg_val */ CASE WHEN M.JOBCODE = 'G' AND VM.month_count > 0 AND ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN COALESCE(TSM.total_inwon, 0) END) / VM.month_count, 0) > 0 THEN CONCAT('[ ', FORMAT(ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN COALESCE(TSM.total_inwon, 0) END) / VM.month_count, 0), 0), ' ] ', FORMAT(ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / VM.month_count, 2), 0)) WHEN M.JOBCODE = 'D' AND VM.month_count > 0 AND COALESCE(SUM(CASE WHEN TSM.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN TSM.total_jinryo END), 0) > 0 AND ROUND((SUM(CASE WHEN TSM.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN TSM.total_gumsa END) / COALESCE(SUM(CASE WHEN TSM.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN TSM.total_jinryo END), 1)) * 100) > 0 THEN CONCAT('[ ', ROUND((SUM(CASE WHEN TSM.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN TSM.total_gumsa END) / COALESCE(SUM(CASE WHEN TSM.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN TSM.total_jinryo END), 1)) * 100), '% ] ', FORMAT(ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / VM.month_count, 2), 0)) ELSE COALESCE( IF(VM.month_count > 0, FORMAT(ROUND(SUM(CASE WHEN M.JOBYYMM IN (#{fr_yymm}, #{midyymm}, #{endyymm}) THEN M.JAMOUNT END) / VM.month_count, 2), 0), 0)) END AS avg_val,
/* ta_f_ym */ CASE WHEN M.JOBCODE = 'G' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_inwon END), 0) > 0 THEN CONCAT('[ ', FORMAT(MAX(CASE WHEN TSM.JOBYYMM = #{fr_yymm} THEN TSM.total_inwon END), 0), ' ] ', FORMAT(ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN FN_TA_HOSP(#{hosp_cd}, #{fr_yymm}, #{make_fg}, M.JOBCODE) END), 0), 0), 0)) WHEN M.JOBCODE = 'D' AND COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{fr_yymm} THEN THS.ta_jinryo END), 0) > 0 AND ROUND((MAX(CASE WHEN THS.JOBYYMM = #{fr_yymm} THEN THS.ta_gumsa END) / COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{fr_yymm} THEN THS.ta_jinryo END), 1)) * 100) > 0 THEN CONCAT('[ ', ROUND((MAX(CASE WHEN THS.JOBYYMM = #{fr_yymm} THEN THS.ta_gumsa END) / COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{fr_yymm} THEN THS.ta_jinryo END), 1)) * 100), '% ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN FN_TA_HOSP(#{hosp_cd}, #{fr_yymm}, #{make_fg}, M.JOBCODE) END), 0), 0)) ELSE FORMAT(ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{fr_yymm} THEN FN_TA_HOSP(#{hosp_cd}, #{fr_yymm}, #{make_fg}, M.JOBCODE) END), 0), 0), 0) END AS ta_f_ym,
/* ta_m_ym */ CASE WHEN M.JOBCODE = 'G' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_inwon END), 0) > 0 THEN CONCAT('[ ', FORMAT(MAX(CASE WHEN TSM.JOBYYMM = #{midyymm} THEN TSM.total_inwon END), 0), ' ] ', FORMAT(ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN FN_TA_HOSP(#{hosp_cd}, #{midyymm}, #{make_fg}, M.JOBCODE) END), 0), 0), 0)) WHEN M.JOBCODE = 'D' AND COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{midyymm} THEN THS.ta_jinryo END), 0) > 0 AND ROUND((MAX(CASE WHEN THS.JOBYYMM = #{midyymm} THEN THS.ta_gumsa END) / COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{midyymm} THEN THS.ta_jinryo END), 1)) * 100) > 0 THEN CONCAT('[ ', ROUND((MAX(CASE WHEN THS.JOBYYMM = #{midyymm} THEN THS.ta_gumsa END) / COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{midyymm} THEN THS.ta_jinryo END), 1)) * 100), '% ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN FN_TA_HOSP(#{hosp_cd}, #{midyymm}, #{make_fg}, M.JOBCODE) END), 0), 0)) ELSE FORMAT(ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{midyymm} THEN FN_TA_HOSP(#{hosp_cd}, #{midyymm}, #{make_fg}, M.JOBCODE) END), 0), 0), 0) END AS ta_m_ym,
/* ta_e_ym */ CASE WHEN M.JOBCODE = 'G' AND COALESCE(MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_inwon END), 0) > 0 THEN CONCAT('[ ', FORMAT(MAX(CASE WHEN TSM.JOBYYMM = #{endyymm} THEN TSM.total_inwon END), 0), ' ] ', FORMAT(ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN FN_TA_HOSP(#{hosp_cd}, #{endyymm}, #{make_fg}, M.JOBCODE) END), 0), 0), 0)) WHEN M.JOBCODE = 'D' AND COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{endyymm} THEN THS.ta_jinryo END), 0) > 0 AND ROUND((MAX(CASE WHEN THS.JOBYYMM = #{endyymm} THEN THS.ta_gumsa END) / COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{endyymm} THEN THS.ta_jinryo END), 1)) * 100) > 0 THEN CONCAT('[ ', ROUND((MAX(CASE WHEN THS.JOBYYMM = #{endyymm} THEN THS.ta_gumsa END) / COALESCE(MAX(CASE WHEN THS.JOBYYMM = #{endyymm} THEN THS.ta_jinryo END), 1)) * 100), '% ] ', FORMAT(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN FN_TA_HOSP(#{hosp_cd}, #{endyymm}, #{make_fg}, M.JOBCODE) END), 0), 0)) ELSE FORMAT(ROUND(COALESCE(SUM(CASE WHEN M.JOBYYMM = #{endyymm} THEN FN_TA_HOSP(#{hosp_cd}, #{endyymm}, #{make_fg}, M.JOBCODE) END), 0), 0), 0) END AS ta_e_ym
FROM TBL_REPORT_MST M LEFT JOIN ValidMonths VM ON M.JOBCODE = VM.JOBCODE LEFT JOIN TotalSummaryMonthly TSM ON M.JOBYYMM = TSM.JOBYYMM LEFT JOIN TaHospSummary THS ON M.JOBYYMM = THS.JOBYYMM WHERE M.HOSP_CD = #{hosp_cd} AND M.JOBYYMM BETWEEN #{fr_yymm} AND #{endyymm} AND M.MAKE_FG = #{make_fg} GROUP BY M.JOBCODE ORDER BY jobcode;

