DELETE FROM TBL_IPWON_INFO 
 WHERE HOSP_CD = #{hosp_cd}
   AND JOBYYMM = #{jobyymm}

DELETE FROM TBL_SPCSUGA_INFO
 WHERE HOSP_CD = #{hosp_cd}
   AND JOBYYMM = #{jobyymm}

mapper.select:
WITH patient_data AS ( SELECT DISTINCT e.PAT_ID AS patId , e.PAT_NM AS patNm , e.MED_START AS medStart , e.DIABETES AS diabeYn , e.HBA1C_TEST AS hba1cYn , e.HBA1C_VALUE / 10 AS eResult , STR_TO_DATE(e.TEST_DATE, '%Y%m%d') AS examiDt , STR_TO_DATE(e.DOC_DT, '%Y%m%d') AS docDt , STR_TO_DATE(e.ADMIT_DT, '%Y%m%d') AS admitDt , MAX(COALESCE(tdm.DIAG_CODE,'')) AS preDiag
FROM TBL_PATVAL_MST e LEFT JOIN TBL_MYOUNG_MST tmm ON tmm.HOSP_CD = e.HOSP_CD AND tmm.PAT_ID = e.PAT_ID JOIN TBL_CHUNG_MST tcm ON tcm.HOSP_CD = tmm.HOSP_CD AND tcm.CLAIM_NO = tmm.CLAIM_NO AND tcm.DATE_YM = DATE_FORMAT(DATE_SUB(CONCAT(#{jobYymm}, '01'), INTERVAL 1 MONTH), '%Y%m') LEFT JOIN TBL_DISEASE_MST tdm ON tdm.HOSP_CD = tmm.HOSP_CD AND tdm.CLAIM_NO = tmm.CLAIM_NO AND tdm.BILL_SEQ = tmm.BILL_SEQ AND LEFT(tdm.DIAG_CODE,3) IN ('E10','E11','E12','E13','E14') /* AND tdm.DIAG_CODE LIKE 'E1%' */ /* AND tdm.DIAG_TYPE = '1' */ WHERE e.HOSP_CD = #{hospCd} AND e.MED_START LIKE CONCAT(#{jobYymm},'%')
AND ( e.EVAL_TYPE = '2' OR ( e.EVAL_TYPE = '3' AND DAY(STR_TO_DATE(e.MED_START, '%Y%m%d')) = 1 AND DAY(STR_TO_DATE(e.DOC_DT, '%Y%m%d')) BETWEEN 7 AND 10 AND NOT EXISTS (SELECT 1 FROM TBL_PATVAL_MST b WHERE b.HOSP_CD = e.HOSP_CD AND b.PAT_ID = e.PAT_ID /* AND b.EVAL_TYPE = '3' */ AND LEFT(b.MED_START, 6) = DATE_FORMAT(DATE_SUB(STR_TO_DATE(e.MED_START, '%Y%m%d'), INTERVAL 1 MONTH), '%Y%m') AND b.DOC_DT = e.DOC_DT) ) OR ( e.DIABETES = '0' AND tdm.DIAG_CODE IS NOT NULL AND LEFT(tdm.DIAG_CODE, 3) IN ('E10','E11','E12','E13','E14') ) )
GROUP BY e.PAT_ID,e.PAT_NM,e.MED_START,e.DIABETES,e.HBA1C_TEST,e.HBA1C_VALUE,e.TEST_DATE,e.DOC_DT,e.ADMIT_DT ) SELECT distinct LEFT(pd.patId,6) AS patId , CASE WHEN CHAR_LENGTH(COALESCE(pd.patNm, '')) >= 1 THEN CONCAT(LEFT(COALESCE(pd.patNm, ''), CHAR_LENGTH(COALESCE(pd.patNm, '')) - 1), '*') ELSE '' END AS patNm , pd.admitDt , pd.medStart , pd.docDt , CASE WHEN pd.diabeYn = 0 THEN '' ELSE pd.diabeYn END AS diabeYn , pd.hba1cYn , pd.preDiag , COALESCE(pd.examiDt,'') AS examiDt , CASE WHEN pd.eResult = 0 THEN '' ELSE pd.eResult END AS eResult
/* , CASE WHEN pd.examiDt IS NOT NULL AND DATEDIFF(pd.docDt, pd.admitDt) <= 90 THEN 'X' WHEN pd.examiDt IS NOT NULL AND REPLACE(pd.examiDt,'-','') > pd.docDt THEN 'X'
WHEN pd.examiDt IS NOT NULL AND DATEDIFF(pd.docDt, REPLACE(pd.examiDt,'-','')) >= 90 THEN '1' WHEN pd.examiDt IS NOT NULL AND DATEDIFF(pd.docDt, REPLACE(pd.examiDt,'-','')) < 0 THEN '2'
WHEN pd.examiDt IS NOT NULL AND pd.eResult >= 8.5 THEN '3'
WHEN pd.examiDt IS NOT NULL AND pd.eResult < 4 THEN '4'
WHEN pd.diabeYn = '1' AND ( pd.examiDt IS NULL OR pd.eResult IS NULL OR pd.eResult = 0 ) THEN '5'
WHEN pd.examiDt IS NOT NULL AND pd.eResult >= 4 AND pd.eResult < 8.5 AND pd.examiDt <= pd.docDt THEN '6'
WHEN pd.preDiag != '' AND pd.diabeYn != '1' THEN 'Y' ELSE '' END AS approYn */ , CASE
/* 입원 후 문서일(docDt)이 3개월(월 기준) 이내이면 'X' */ WHEN pd.examiDt IS NOT NULL AND pd.docDt < DATE_ADD(pd.admitDt, INTERVAL 3 MONTH) THEN 'X'
/* 검사일이 문서일보다 미래이면 'X' */ WHEN pd.examiDt IS NOT NULL AND REPLACE(pd.examiDt,'-','') > pd.docDt THEN 'X'
/* 검사일로부터 3개월 경과 후 문서가 작성되면 '1' */ WHEN pd.examiDt IS NOT NULL AND pd.docDt > DATE_ADD(STR_TO_DATE(pd.examiDt, '%Y-%m-%d'), INTERVAL 3 MONTH) THEN '1'
/* 검사일이 문서일보다 미래이면 '2' */ WHEN pd.examiDt IS NOT NULL AND pd.docDt < STR_TO_DATE(pd.examiDt, '%Y-%m-%d') THEN '2'
/* 검사값이 8.5 이상이면 '3' */ WHEN pd.examiDt IS NOT NULL AND pd.eResult >= 8.5 THEN '3'
/* 검사값이 4 미만이면 '4' */ WHEN pd.examiDt IS NOT NULL AND pd.eResult < 4 THEN '4'
/* 당뇨 진단인데 검사값이 없거나 0이면 '5' */ WHEN (pd.diabeYn = '1') AND (pd.examiDt IS NULL OR pd.eResult IS NULL OR pd.eResult = 0) THEN '5'
/* 검사값이 4 이상, 8.5 미만이고 검사일이 문서일 이전이면 '6' */ WHEN pd.examiDt IS NOT NULL AND pd.eResult >= 4 AND pd.eResult < 8.5 AND pd.examiDt <= pd.docDt THEN '6'
/* 과거 진단이 있고, 당뇨 진단이 아닌 경우 'Y' */ WHEN pd.preDiag != '' AND pd.diabeYn != '1' THEN 'Y'
ELSE '' END AS approYn
, FN_TEWON_CHECK(#{hospCd},#{jobYymm},pd.admitDt,pd.patNm) AS tewonYn
FROM patient_data pd

WITH filtered_pat AS ( SELECT pm1.PAT_ID FROM TBL_PATVAL_MST pm1 WHERE pm1.HOSP_CD = #{hospCd}
AND pm1.MED_START BETWEEN CONCAT(CASE WHEN CAST(SUBSTRING(#{jobYymm},5,2) AS UNSIGNED) <= 6 THEN #{jobYymm} ELSE CONCAT(SUBSTRING(#{jobYymm},1,4),'07') END, '01') AND CONCAT(#{jobYymm}, '31')
GROUP BY pm1.PAT_ID HAVING SUM(CASE WHEN LEFT(IFNULL(pm1.PAT_CLASS,PATIENT_CLASSIFICATION(pm1.HOSP_CD, pm1.PAT_ID, pm1.CHUNGSEQ, pm1.CLFORM_VER, pm1.ADMIT_DT, pm1.MED_START)),1) NOT IN ('D','E') THEN 1 ELSE 0 END) = 0 /* A31(중도입원) 이력 있는 환자 전체 제외 */ AND SUM(CASE WHEN IFNULL(pm1.PAT_CLASS, PATIENT_CLASSIFICATION(pm1.HOSP_CD, pm1.PAT_ID, pm1.CHUNGSEQ, pm1.CLFORM_VER, pm1.ADMIT_DT, pm1.MED_START)) = 'A31' THEN 1 ELSE 0 END) = 0 ) SELECT DISTINCT LEFT(pm2.PAT_ID,6) AS patId , CASE WHEN CHAR_LENGTH(COALESCE(pm2.PAT_NM, '')) >= 1 THEN CONCAT(LEFT(COALESCE(pm2.PAT_NM, ''), CHAR_LENGTH(COALESCE(pm2.PAT_NM, '')) - 1), '*') ELSE '' END AS patNm , pm2.ADMIT_DT AS admitDt , pm2.MED_START AS medStart , pm2.DOC_DT AS docDt , CASE WHEN IFNULL(pm2.PAT_CLASS,'') = '' THEN LEFT(PATIENT_CLASSIFICATION(pm2.HOSP_CD, pm2.PAT_ID, pm2.CHUNGSEQ, pm2.CLFORM_VER, pm2.ADMIT_DT, pm2.MED_START),1) ELSE LEFT(pm2.PAT_CLASS,1) END AS cPatClass , CASE WHEN LEFT(IFNULL(pm2.PAT_CLASS,PATIENT_CLASSIFICATION(pm2.HOSP_CD, pm2.PAT_ID, pm2.CHUNGSEQ, pm2.CLFORM_VER, pm2.ADMIT_DT, pm2.MED_START)),1) IN ('D','E') AND (
/* 현재 입원 기간 180일 이상 */ DATEDIFF(COALESCE(ii.TEWONDT, DATE_FORMAT(pm2.DOC_DT,'%Y%m%d')), DATE_FORMAT(pm2.ADMIT_DT,'%Y%m%d')) + 1 >= 181
OR /* 이전 입원 내역 있을 때 년도 기준 누적 180일 이상 */ EXISTS ( SELECT 1 FROM TBL_IPWON_INFO prev_ii WHERE prev_ii.HOSP_CD = #{hospCd} AND LEFT(prev_ii.JUMINNO,6) = LEFT(pm2.PAT_ID,6) AND prev_ii.PATNAME = REGEXP_REPLACE(pm2.PAT_NM,'[0-9]','') AND COALESCE(prev_ii.TEWONDT,'') != ''
AND REPLACE(prev_ii.TEWONDT,'-','') < REPLACE(pm2.ADMIT_DT,'-','') AND DATEDIFF( STR_TO_DATE(REPLACE(COALESCE(ii.TEWONDT, DATE_FORMAT(pm2.DOC_DT,'%Y%m%d')),'-',''),'%Y%m%d'), CASE WHEN LEFT(REPLACE(prev_ii.IPWONDT,'-',''),4) < LEFT(pm2.ADMIT_DT,4) THEN STR_TO_DATE(CONCAT(LEFT(pm2.ADMIT_DT,4),'0101'),'%Y%m%d') ELSE STR_TO_DATE(REPLACE(prev_ii.IPWONDT,'-',''),'%Y%m%d') END ) + 1 >= 181
) ) THEN 'Y' ELSE '' END AS longAdm , CASE WHEN LEFT(IFNULL(pm2.PAT_CLASS,PATIENT_CLASSIFICATION(pm2.HOSP_CD, pm2.PAT_ID, pm2.CHUNGSEQ, pm2.CLFORM_VER, pm2.ADMIT_DT, pm2.MED_START)),1) IN ('A','B','C') THEN 'Y' ELSE '' END AS approYn FROM TBL_PATVAL_MST pm2 LEFT JOIN TBL_IPWON_INFO ii ON ii.HOSP_CD = pm2.HOSP_CD
AND ii.JOBYYMM BETWEEN CASE WHEN CAST(SUBSTRING(#{jobYymm},5,2) AS UNSIGNED) <= 6 THEN #{jobYymm} ELSE CONCAT(SUBSTRING(#{jobYymm},1,4), '07') END AND #{jobYymm}
AND LEFT(ii.JUMINNO,6) = LEFT(pm2.PAT_ID,6) AND REPLACE(ii.IPWONDT,'-','') = pm2.ADMIT_DT AND COALESCE(ii.TEWONDT,'') != '' AND #{jobYymm} >= LEFT(REPLACE(ii.TEWONDT,'-',''),6) AND pm2.PAT_NM = REGEXP_REPLACE(ii.PATNAME, '[0-9]', '') WHERE pm2.HOSP_CD = #{hospCd} AND pm2.PAT_ID IN (SELECT fp.PAT_ID FROM filtered_pat fp) /* A31 입원건 자체도 명단에서 제외 */ AND IFNULL(pm2.PAT_CLASS, PATIENT_CLASSIFICATION(pm2.HOSP_CD, pm2.PAT_ID, pm2.CHUNGSEQ, pm2.CLFORM_VER, pm2.ADMIT_DT, pm2.MED_START)) != 'A31'
AND pm2.MED_START BETWEEN CONCAT(CASE WHEN CAST(SUBSTRING(#{jobYymm},5,2) AS UNSIGNED) <= 6 THEN #{jobYymm} ELSE CONCAT(SUBSTRING(#{jobYymm},1,4), '07') END, '01') AND CONCAT(#{jobYymm}, '31')

SELECT DISTINCT hm.HOSP_CD AS hosp_cd , hm.HOSP_NM AS hosp_nm FROM TBL_HOSP_MST hm WHERE 1=1 AND hm.ACTION_YN = 'Y'
AND hm.HOSP_CD = #{hosp_cd}
ORDER BY hm.HOSP_NM

		SELECT IFNULL(a.HTTP_PH,'') as http_st
		  FROM TBL_GOOGLE_ST a
		 WHERE a.HOSP_CD  = #{hosp_cd}
           AND a.JOBYYMM  = #{jobyymm}
           AND a.JOBCODE  = #{jobcode}
         LIMIT 1

SELECT b.FILE_NM
     , b.LINEVAL
     , CAST(((CHAR_LENGTH(b.LINEVAL) + (LENGTH(b.LINEVAL) - CHAR_LENGTH(b.LINEVAL)) / 2)-1) AS UNSIGNED) AS VALSIZE
  FROM TBL_FILES_DATA b
 INNER JOIN (
       SELECT s.FILE_NM AS GRP_FILE_NM
            , CAST(((CHAR_LENGTH(s.LINEVAL) + (LENGTH(s.LINEVAL) - CHAR_LENGTH(s.LINEVAL)) / 2)-1) AS UNSIGNED) AS GRP_VALSIZE
            , MIN(s.LINE_NO) AS MIN_LINE_NO
         FROM TBL_FILES_DATA s
        WHERE s.HOSP_CD = #{hosp_cd}
          AND s.MG_YEAR = #{mg_year}
          AND s.MGMONTH = #{mgmonth}
          AND s.MG_FLAG = #{mg_flag}


          AND s.JOBS_DT = #{jobs_dt}


          AND s.JOBS_DT = (SELECT MAX(d.JOBS_DT) FROM TBL_FILES_DATA d
                            WHERE d.HOSP_CD = #{hosp_cd} AND d.MG_YEAR = #{mg_year}
                              AND d.MGMONTH = #{mgmonth} AND d.MG_FLAG = #{mg_flag})


        GROUP BY s.FILE_NM,
                 CAST(((CHAR_LENGTH(s.LINEVAL) + (LENGTH(s.LINEVAL) - CHAR_LENGTH(s.LINEVAL)) / 2)-1) AS UNSIGNED)
       HAVING GRP_VALSIZE >= 9
       ) g ON b.FILE_NM = g.GRP_FILE_NM
          AND b.LINE_NO = g.MIN_LINE_NO
          AND CAST(((CHAR_LENGTH(b.LINEVAL) + (LENGTH(b.LINEVAL) - CHAR_LENGTH(b.LINEVAL)) / 2)-1) AS UNSIGNED) = g.GRP_VALSIZE
 WHERE b.HOSP_CD = #{hosp_cd}
   AND b.MG_YEAR = #{mg_year}
   AND b.MGMONTH = #{mgmonth}
   AND b.MG_FLAG = #{mg_flag}


   AND b.JOBS_DT = #{jobs_dt}


   AND b.JOBS_DT = (SELECT MAX(d.JOBS_DT) FROM TBL_FILES_DATA d
                     WHERE d.HOSP_CD = #{hosp_cd} AND d.MG_YEAR = #{mg_year}
                       AND d.MGMONTH = #{mgmonth} AND d.MG_FLAG = #{mg_flag})


 ORDER BY b.FILE_NM, VALSIZE DESC

SELECT f.sam_ver AS SAMVER , f.tblinfo AS TBLINFO , f.version AS VERSION , f.colsize AS COLSIZE FROM ( SELECT e.samver AS sam_ver , e.tblinfo , e.version , SUM(CASE WHEN e.db_comcolnm = 'X' THEN 0 ELSE e.col_size END) AS colsize FROM TBL_SAMFVER_MST e GROUP BY e.samver, e.tblinfo, e.version ) f WHERE f.version = #{version}
AND f.colsize = #{valsize}
AND f.sam_ver = #{samver} LIMIT 1

