UPDATE TBL_PATVAL_MST
   SET USE_YN    = #{useYn}
     , UPD_DTTM  = NOW()
     , UPD_USER  = #{updUser}
 WHERE HOSP_CD   = #{hospCd}
   AND PAT_ID    = #{patId}
   AND ADMIT_DT  = #{admitDt}
   AND MED_START = #{medStart}
